patch:
diff --git a/src/main/java/org/apache/commons/lang3/time/DurationFormatUtils.java b/src/main/java/org/apache/commons/lang3/time/DurationFormatUtils.java
--- a/src/main/java/org/apache/commons/lang3/time/DurationFormatUtils.java
+++ b/src/main/java/org/apache/commons/lang3/time/DurationFormatUtils.java
@@ -514,48 +503,41 @@
     }

     /**
-     * <p>Formats the time gap as a string, using the specified format.
-     * Padding the left-hand side side of numbers with zeroes is optional and
-     * the time zone may be specified.
+     * <p>
+     * Formats the time gap as a string, using the specified format. Padding the left-hand side side of numbers with zeroes is optional and the time zone may be
+     * specified.
+     * <p>
+     * When calculating the difference between months/days, it chooses to calculate months first. So when working out the number of months and days between
+     * January 15th and March 10th, it choose 1 month and 23 days gained by choosing January-&gt;February = 1 month and then calculating days forwards, and not
+     * the 1 month and 26 days gained by choosing March -&gt; February = 1 month and then calculating days backwards.
+     * </p>
+     * <p>
+     * For more control, the <a href="https://www.joda.org/joda-time/">Joda-Time</a> library is recommended.
+     * </p>
      *
-     * <p>When calculating the difference between months/days, it chooses to
-     * calculate months first. So when working out the number of months and
-     * days between January 15th and March 10th, it choose 1 month and
-     * 23 days gained by choosing January-&gt;February = 1 month and then
-     * calculating days forwards, and not the 1 month and 26 days gained by
-     * choosing March -&gt; February = 1 month and then calculating days
-     * backwards.</p>
-     *
-     * <p>For more control, the <a href="https://www.joda.org/joda-time/">Joda-Time</a>
-     * library is recommended.</p>
-     *
-     * @param startMillis  the start of the duration
-     * @param endMillis  the end of the duration
-     * @param format  the way in which to format the duration, not null
-     * @param padWithZeros  whether to pad the left-hand side side of numbers with 0's
-     * @param timezone  the millis are defined in
-     * @return the formatted duration, not null
-     * @throws IllegalArgumentException if startMillis is greater than endMillis
+     * @param startMillis  the start of the duration.
+     * @param endMillis    the end of the duration.
+     * @param format       the way in which to format the duration, not null.
+     * @param padWithZeros whether to pad the left-hand side side of numbers with 0's.
+     * @param timezone     the millis are defined in.
+     * @return the formatted duration, not null.
+     * @throws IllegalArgumentException if startMillis is greater than endMillis.
      */
     public static String formatPeriod(final long startMillis, final long endMillis, final String format, final boolean padWithZeros,
             final TimeZone timezone) {
         Validate.isTrue(startMillis <= endMillis, "startMillis must not be greater than endMillis");
-
         // Used to optimize for differences under 28 days and
         // called formatDuration(millis, format); however this did not work
         // over leap years.
         // TODO: Compare performance to see if anything was lost by
         // losing this optimization.
-
         final Token[] tokens = lexx(format);
-
         // time zones get funky around 0, so normalizing everything to GMT
         // stops the hours being off
         final Calendar start = Calendar.getInstance(timezone);
         start.setTime(new Date(startMillis));
         final Calendar end = Calendar.getInstance(timezone);
         end.setTime(new Date(endMillis));
-
         // initial estimates
         long milliseconds = end.get(Calendar.MILLISECOND) - start.get(Calendar.MILLISECOND);
         int seconds = end.get(Calendar.SECOND) - start.get(Calendar.SECOND);
@@ -564,7 +546,6 @@
         int days = end.get(Calendar.DAY_OF_MONTH) - start.get(Calendar.DAY_OF_MONTH);
         int months = end.get(Calendar.MONTH) - start.get(Calendar.MONTH);
         int years = end.get(Calendar.YEAR) - start.get(Calendar.YEAR);
-
         // each initial estimate is adjusted in case it is under 0
         while (milliseconds < 0) {
             milliseconds += DateUtils.MILLIS_PER_SECOND;
@@ -582,19 +563,16 @@
             hours += HOURS_PER_DAY;
             days -= 1;
         }
-
         if (Token.containsTokenWithValue(tokens, M)) {
             while (days < 0) {
                 days += start.getActualMaximum(Calendar.DAY_OF_MONTH);
                 months -= 1;
                 start.add(Calendar.MONTH, 1);
             }
-
             while (months < 0) {
                 months += 12;
                 years -= 1;
             }
-
             if (!Token.containsTokenWithValue(tokens, y) && years != 0) {
                 while (years != 0) {
                     months += 12 * years;
@@ -603,51 +581,37 @@
             }
         } else {
             // there are no M's in the format string
-
             if (!Token.containsTokenWithValue(tokens, y)) {
                 int target = end.get(Calendar.YEAR);
                 if (months < 0) {
                     // target is end-year -1
                     target -= 1;
                 }
-
                 while (start.get(Calendar.YEAR) != target) {
                     days += start.getActualMaximum(Calendar.DAY_OF_YEAR) - start.get(Calendar.DAY_OF_YEAR);
-
                     // Not sure I grok why this is needed, but the brutal tests show it is
-                    if (start instanceof GregorianCalendar &&
-                            start.get(Calendar.MONTH) == Calendar.FEBRUARY &&
-                            start.get(Calendar.DAY_OF_MONTH) == 29) {
+                    if (start instanceof GregorianCalendar && start.get(Calendar.MONTH) == Calendar.FEBRUARY && start.get(Calendar.DAY_OF_MONTH) == 29) {
                         days += 1;
                     }
-
                     start.add(Calendar.YEAR, 1);
-
                     days += start.get(Calendar.DAY_OF_YEAR);
                 }
-
                 years = 0;
             }
-
             while (start.get(Calendar.MONTH) != end.get(Calendar.MONTH)) {
                 days += start.getActualMaximum(Calendar.DAY_OF_MONTH);
                 start.add(Calendar.MONTH, 1);
             }
-
             months = 0;
-
             while (days < 0) {
                 days += start.getActualMaximum(Calendar.DAY_OF_MONTH);
                 months -= 1;
                 start.add(Calendar.MONTH, 1);
             }
-
         }
-
         // The rest of this code adds in values that
         // aren't requested. This allows the user to ask for the
         // number of months and get the real count and not just 0->11.
-
         if (!Token.containsTokenWithValue(tokens, d)) {
             hours += HOURS_PER_DAY * days;
             days = 0;
@@ -664,6 +628,5 @@
             milliseconds += DateUtils.MILLIS_PER_SECOND * seconds;
             seconds = 0;
         }
-
         return format(tokens, years, months, days, hours, minutes, seconds, milliseconds, padWithZeros);
     }
